const ASSETS = {"/index.html":{"body":"","type":"text/html; charset=utf-8"},"/styles.css":{"body":"","type":"text/css; charset=utf-8"},"/app.js":{"body":"","type":"text/javascript; charset=utf-8"},"/manifest.json":{"body":"","type":"application/json; charset=utf-8"},"/service-worker.js":{"body":"","type":"text/javascript; charset=utf-8"},"/icon.svg":{"body":"","type":"image/svg+xml; charset=utf-8"},"/public/mobilepay-qr.png":{"body":"","type":"image/png"},"/public/login-background.jpg":{"body":"","type":"image/jpeg"},"/":{"body":"","type":"text/html; charset=utf-8"}};

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname.endsWith("/") && url.pathname !== "/" ? url.pathname.slice(0, -1) : url.pathname;
    const asset = ASSETS[path] || ASSETS[path + ".html"] || ASSETS["/index.html"];
    const headers = new Headers({
      "content-type": asset.type,
      "cache-control": path === "/index.html" || path === "/" ? "no-store" : "public, max-age=3600",
    });
    const body = Uint8Array.from(atob(asset.body), (char) => char.charCodeAt(0));
    return new Response(body, { headers });
  },
};
